import React from "react";

const Story = () => (
  <section id="story" className="card">
    <h3>Our Story</h3>
    <p>
      It all began when Adarsh and Karthika crossed paths in the most unexpected way.
      From friendship to love, every moment has been a journey of laughter, trust, and dreams.
      We can’t wait to start this new chapter with you by our side.
    </p>
  </section>
);

export default Story;
